// Package verify provides verification helpers for agent completion.
package verify

import "strings"

// SkillClass represents the category of work a skill performs.
type SkillClass string

const (
	// SkillClassCodeProducing skills produce code changes that require testing and synthesis.
	SkillClassCodeProducing SkillClass = "code-producing"

	// SkillClassKnowledgeProducing skills produce knowledge artifacts (investigations, decisions, audits).
	// These skills don't require test evidence or synthesis since the artifact IS the deliverable.
	SkillClassKnowledgeProducing SkillClass = "knowledge-producing"

	// SkillClassUnknown is for skills not explicitly categorized.
	SkillClassUnknown SkillClass = "unknown"
)

// codeProducingSkills are skills that produce code changes requiring testing and synthesis.
var codeProducingSkills = map[string]bool{
	"feature-impl":         true, // Primary implementation skill
	"systematic-debugging": true, // Debug fixes should be tested
	"reliability-testing":  true, // Testing skill should document tests
}

// knowledgeProducingSkills are skills that produce knowledge artifacts as deliverables.
// These skills may incidentally modify code (e.g., investigation updating models)
// but their primary deliverable is the knowledge artifact, not code changes.
var knowledgeProducingSkills = map[string]bool{
	"investigation":  true, // Research skill, produces investigations
	"architect":      true, // Design skill, produces decisions/recommendations
	"research":       true, // External research, produces research reports
	"design-session": true, // Scoping skill, produces epics
	"codebase-audit": true, // Audit skill, produces audit reports
	"issue-creation": true, // Triage skill, creates issues (no code changes)
	"writing-skills": true, // Meta skill, modifies skills (documentation work)
}

// ClassifySkill returns the skill class for a given skill name.
func ClassifySkill(skillName string) SkillClass {
	if skillName == "" {
		return SkillClassUnknown
	}

	skillName = strings.ToLower(skillName)

	if codeProducingSkills[skillName] {
		return SkillClassCodeProducing
	}

	if knowledgeProducingSkills[skillName] {
		return SkillClassKnowledgeProducing
	}

	return SkillClassUnknown
}

// IsCodeProducingSkill returns true if the skill produces code changes requiring testing.
func IsCodeProducingSkill(skillName string) bool {
	return ClassifySkill(skillName) == SkillClassCodeProducing
}

// IsKnowledgeProducingSkill returns true if the skill produces knowledge artifacts.
func IsKnowledgeProducingSkill(skillName string) bool {
	return ClassifySkill(skillName) == SkillClassKnowledgeProducing
}

// IsSkillRequiringSynthesis determines if a skill requires SYNTHESIS.md.
// Knowledge-producing skills don't require synthesis because the artifact IS the deliverable.
// Code-producing skills require synthesis to document what changed and why.
// Unknown skills require synthesis (conservative default).
func IsSkillRequiringSynthesis(skillName string) bool {
	if skillName == "" {
		return true // Conservative default
	}

	// Knowledge-producing skills don't need synthesis - the artifact is the deliverable
	if IsKnowledgeProducingSkill(skillName) {
		return false
	}

	// Code-producing and unknown skills require synthesis
	return true
}

